// customIcons holds IoTMaker-specific icons that are not part of FontAwesome.
// These are injected into iconDefs by this file's init() so they survive the
// faIconsGenerated.go init() that replaces the entire map.
//
// Go guarantees init() execution order within a package follows filename
// lexicographic order. Since "falcons.go" > "faIconsGenerated.go", this
// init() always runs AFTER the generated file, making the injection safe.
//
// To add a new custom icon:
//  1. Define the path constant (KFA...) in the const block above.
//  2. Add an entry to the customIcons map below.
var customIcons = map[string]FAIconDef{
	"serial": {KFASerial, "0 0 512 512"},
}

func init() {
	for name, def := range customIcons {
		iconDefs[name] = def
	}
}
